class AllOne {
    private HashMap<String, Integer> countMap;
    private TreeMap<Integer, HashSet<String>> freqMap;

    public AllOne() {
        countMap = new HashMap<>();
        freqMap = new TreeMap<>();
    }

    public void inc(String key) {
        if (countMap.containsKey(key)) {
            int count = countMap.get(key);
            freqMap.get(count).remove(key);
            if (freqMap.get(count).size() == 0) {
                freqMap.remove(count);
            }
            countMap.put(key, count + 1);
            freqMap.computeIfAbsent(count + 1, z -> new HashSet<>()).add(key);
        } else {
            countMap.put(key, 1);
            freqMap.computeIfAbsent(1, z -> new HashSet<>()).add(key);
        }
    }

    public void dec(String key) {
        if (countMap.containsKey(key)) {
            int count = countMap.get(key);
            freqMap.get(count).remove(key);
            if (freqMap.get(count).size() == 0) {
                freqMap.remove(count);
            }
            if (count > 1) {
                countMap.put(key, count - 1);
                freqMap.computeIfAbsent(count - 1, z -> new HashSet<>()).add(key);
            } else {
                countMap.remove(key);
            }
        }
    }

    public String getMaxKey() {
        if (freqMap.size() == 0) {
            return "";
        }
        return freqMap.lastEntry().getValue().iterator().next();
    }

    public String getMinKey() {
        if (freqMap.size() == 0) {
            return "";
        }
        return freqMap.firstEntry().getValue().iterator().next();
    }
}
